compliant_code:
func handleRequest(w http.ResponseWriter, r *http.Request) {
    req, err := parseRequest(r)
    if err != nil {
        http.Error(w, err.Error(), 400)
        return
    }
    result, err := processRequest(req)
    if err != nil {
        http.Error(w, err.Error(), 500)
        return
    }
    writeJSON(w, result)
}
